import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { chaptersAPI, progressAPI } from '../services/api';
import './Learn.css';

const Learn = () => {
  const [chapters, setChapters] = useState([]);
  const [userProgress, setUserProgress] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [expandedChapter, setExpandedChapter] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [chaptersResponse, progressResponse] = await Promise.all([
        chaptersAPI.getAll(),
        progressAPI.getLessonProgress()
      ]);

      setChapters(chaptersResponse.data);
      setUserProgress(progressResponse.data);

      console.log('Chapters:', chaptersResponse.data);
      console.log('Progress:', progressResponse.data);
    } catch (err) {
      console.error('Error fetching data:', err);
      setError('Failed to load chapters and lessons');
    } finally {
      setLoading(false);
    }
  };

  const getLessonProgress = (chapterId, lessonId) => {
    const progress = userProgress.find(
      (p) => {
        const chapterMatch = p.chapterId.toString() === chapterId.toString();
        const lessonMatch = p.lessonId.toString() === lessonId.toString();
        return chapterMatch && lessonMatch;
      }
    );
    return progress;
  };

  const calculateChapterStatus = (chapter) => {
    const completedLessons = chapter.lessons.filter(lesson => {
      const progress = getLessonProgress(chapter._id, lesson._id);
      return progress !== undefined && progress !== null;
    });

    if (completedLessons.length === 0) {
      return {
        status: 'NOT STARTED',
        badge: 'not-started',
        avgWPM: 0,
        avgAccuracy: 0,
        progress: 0,
        completedLessons: 0,
        totalLessons: chapter.lessons.length,
        color: '#d1d5db'
      };
    }

    const totalWPM = completedLessons.reduce((sum, lesson) => {
      const progress = getLessonProgress(chapter._id, lesson._id);
      return sum + (progress?.bestWPM || 0);
    }, 0);

    const totalAccuracy = completedLessons.reduce((sum, lesson) => {
      const progress = getLessonProgress(chapter._id, lesson._id);
      return sum + (progress?.bestAccuracy || 0);
    }, 0);

    const avgWPM = Math.round(totalWPM / completedLessons.length);
    const avgAccuracy = Math.round(totalAccuracy / completedLessons.length);
    const progressPercent = Math.round((completedLessons.length / chapter.lessons.length) * 100);

    let status, badge, color;

    // Determine status
    if (avgAccuracy < 70 || avgWPM < 15) {
      status = 'NEEDS PRACTICE';
      badge = 'needs-practice';
      color = '#ef4444';
    } else if (avgAccuracy >= 97 && avgWPM >= 50) {
      status = 'MASTER';
      badge = 'master';
      color = '#f59e0b';
    } else if (avgAccuracy >= 92 && avgWPM >= 35) {
      status = 'ADVANCED';
      badge = 'advanced';
      color = '#3b82f6';
    } else if (avgAccuracy >= 85 && avgWPM >= 25) {
      status = 'INTERMEDIATE';
      badge = 'intermediate';
      color = '#10b981';
    } else if (progressPercent >= 50 && completedLessons.length > 0) {
      status = 'IN PROGRESS';
      badge = 'in-progress';
      color = '#3b82f6';
    } else {
      status = 'BEGINNER';
      badge = 'beginner';
      color: '#fbbf24';
    }

    // Override if completed all lessons
    if (progressPercent === 100 && badge !== 'master') {
      status = 'COMPLETED';
      badge = 'completed';
      color = '#10b981';
    }

    return {
      status,
      badge,
      avgWPM,
      avgAccuracy,
      progress: progressPercent,
      completedLessons: completedLessons.length,
      totalLessons: chapter.lessons.length,
      color
    };
  };

  const getProgressBarColor = (progress, badge) => {
    if (progress === 0) return '#d1d5db';
    if (badge === 'master') return '#f59e0b';
    if (progress >= 90) return '#10b981';
    if (progress >= 50) return '#8b5cf6';
    return '#3b82f6';
  };

  const toggleChapter = (chapterId) => {
    setExpandedChapter(expandedChapter === chapterId ? null : chapterId);
  };

  const handleLessonClick = (chapterId, lessonId) => {
    navigate(`/lesson/${chapterId}/${lessonId}`);
  };

  if (loading) {
    return <div className="loading">Loading chapters...</div>;
  }

  if (error) {
    return (
      <div className="container">
        <div className="error">{error}</div>
        <button className="btn btn-primary" onClick={() => navigate('/dashboard')}>
          Back to Dashboard
        </button>
      </div>
    );
  }

  return (
    <div className="container">
      <div className="learn-header-gradient">
        <h2>Learn Mode - Master Touch Typing</h2>
        <p className="learn-subtitle">
          Progress through 13 chapters to master all keys on the keyboard
        </p>
      </div>

      <div className="chapters-accordion">
        {chapters.map((chapter) => {
          const chapterStatus = calculateChapterStatus(chapter);
          const isExpanded = expandedChapter === chapter._id;

          return (
            <div 
              key={chapter._id} 
              className={`chapter-card-redesigned ${isExpanded ? 'expanded' : ''}`}
            >
              <div 
                className="chapter-header-redesigned"
                onClick={() => toggleChapter(chapter._id)}
              >
                <div className="chapter-title-section">
                  <h3 className="chapter-title-centered">
                    Chapter {chapter.chapterNumber}: {chapter.chapterTitle}
                  </h3>
                  <p className="chapter-description">{chapter.description}</p>
                </div>

                <div className="chapter-right-section">
                  <span className={`status-badge-pill ${chapterStatus.badge}`}>
                    {chapterStatus.status === 'MASTER' && '⭐ '}
                    {chapterStatus.status}
                  </span>
                  <div className="dropdown-arrow-improved">
                    {isExpanded ? '▼' : '▶'}
                  </div>
                </div>
              </div>

              {chapterStatus.progress > 0 && (
                <div className="chapter-progress-info">
                  <span className="stat-item">⚡ {chapterStatus.avgWPM} WPM</span>
                  <span className="stat-item">✓ {chapterStatus.avgAccuracy}%</span>
                  <span className="stat-item">
                    📚 {chapterStatus.completedLessons}/{chapterStatus.totalLessons} Lessons
                  </span>
                </div>
              )}

              <div className="progress-bar-container">
                <div 
                  className="progress-bar-fill"
                  style={{ 
                    width: `${chapterStatus.progress}%`,
                    backgroundColor: getProgressBarColor(chapterStatus.progress, chapterStatus.badge)
                  }}
                />
              </div>

              {isExpanded && (
                <div className="lessons-list-redesigned">
                  {chapter.lessons.map((lesson) => {
                    const progress = getLessonProgress(chapter._id, lesson._id);
                    const isCompleted = progress !== undefined && progress !== null;

                    return (
                      <div
                        key={lesson._id}
                        className="lesson-card-redesigned"
                      >
                        <div className="lesson-info-section">
                          <h4 className="lesson-title-line">
                            Lesson {lesson.lessonNumber} – {lesson.lessonTitle}
                          </h4>
                          <p className="lesson-meta-info">
                            {lesson.lessonType === 'intro' && '🔤 Introduction'}
                            {lesson.lessonType === 'random-words' && '🎲 Random Words'}
                            {lesson.lessonType === 'meaningful-words' && '📝 Meaningful Words'}
                            {lesson.lessonType === 'sentences' && '📄 Sentences'}
                            {lesson.lessonType === 'paragraph' && '📖 Paragraph'}
                            {' • '}⏱️ {lesson.duration} min
                            {lesson.keysIntroduced.length > 0 && (
                              <span className="new-keys-badge">
                                {' • '}New: {lesson.keysIntroduced.join(', ')}
                              </span>
                            )}
                          </p>
                          {isCompleted && (
                            <div className="lesson-stats-inline">
                              <span className="stat-badge wpm">⚡ {progress.bestWPM} WPM</span>
                              <span className="stat-badge accuracy">✓ {progress.bestAccuracy}%</span>
                              <span className="stat-badge attempts">🔄 {progress.attempts}x</span>
                            </div>
                          )}
                        </div>

                        <div className="lesson-action-buttons">
                          <button
                            className="btn-start-lesson"
                            onClick={() => handleLessonClick(chapter._id, lesson._id)}
                          >
                            {isCompleted ? 'Practice Again' : 'Start'}
                          </button>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}
      </div>

      <button
        className="btn btn-secondary back-button"
        onClick={() => navigate('/dashboard')}
      >
        ← Back to Dashboard
      </button>
    </div>
  );
};

export default Learn;
